import{_ as d,o as a,c as e,a2 as o}from"./chunks/framework.CE5oItKu.js";const g=JSON.parse('{"title":"Grid Layout 自定义栅格布局使用说明","description":"","frontmatter":{},"headers":[],"relativePath":"mango/mango-platform/mango-grid-layout/README.md","filePath":"mango/mango-platform/mango-grid-layout/README.md"}'),i={name:"mango/mango-platform/mango-grid-layout/README.md"};function r(s,t,l,n,h,p){return a(),e("div",null,[...t[0]||(t[0]=[o(`<h1 id="grid-layout-自定义栅格布局使用说明" tabindex="-1">Grid Layout 自定义栅格布局使用说明 <a class="header-anchor" href="#grid-layout-自定义栅格布局使用说明" aria-label="Permalink to &quot;Grid Layout 自定义栅格布局使用说明&quot;">​</a></h1><h2 id="_1-概览" tabindex="-1">1. 概览 <a class="header-anchor" href="#_1-概览" aria-label="Permalink to &quot;1. 概览&quot;">​</a></h2><p><code>mango-grid-layout</code> 提供当前登录用户的自定义栅格布局保存、查询和删除能力，配合前端 <code>@mango/grid-layout</code> 使用。它面向工作台、看板、业务驾驶舱、详情页自定义面板等需要按用户保存页面布局的场景。</p><p>模块主要服务 Mango 开发者、业务开发者和 AI Agent。后端只保存用户对某个 <code>pageCode</code> 的布局 JSON，不维护业务小组件数据、不维护默认布局、不负责前端拖拽算法，也不做小组件权限过滤。</p><h2 id="_2-功能清单" tabindex="-1">2. 功能清单 <a class="header-anchor" href="#_2-功能清单" aria-label="Permalink to &quot;2. 功能清单&quot;">​</a></h2><table tabindex="0"><thead><tr><th>能力</th><th>用途</th><th>常用入口</th></tr></thead><tbody><tr><td>查询个人布局</td><td>获取当前登录人在某个页面保存的布局</td><td><code>GET /grid-layout/personal</code></td></tr><tr><td>保存个人布局</td><td>写入或覆盖当前登录人在某个页面的布局</td><td><code>PUT /grid-layout/personal</code></td></tr><tr><td>删除个人布局</td><td>清空个人布局，前端回到默认布局</td><td><code>DELETE /grid-layout/personal</code></td></tr><tr><td>Java API</td><td>供后端模块内或跨模块调用</td><td><code>GridLayoutPersonalApi</code></td></tr><tr><td>数据校验</td><td>校验 <code>pageCode</code>、布局 JSON、栅格宽度和坐标</td><td><code>GridLayoutPersonalService</code></td></tr><tr><td>租户用户隔离</td><td>按当前登录租户、用户和页面编码隔离布局</td><td><code>MangoContextHolder</code></td></tr><tr><td>自动装配</td><td>引入 starter 后注册服务和 Controller</td><td><code>mango-grid-layout-starter</code></td></tr></tbody></table><h2 id="_3-接入方式" tabindex="-1">3. 接入方式 <a class="header-anchor" href="#_3-接入方式" aria-label="Permalink to &quot;3. 接入方式&quot;">​</a></h2><p>后端应用引入 starter：</p><div class="language-xml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">xml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">dependency</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">groupId</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;io.mango.platform.gridlayout&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">groupId</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">artifactId</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;mango-grid-layout-starter&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">artifactId</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">dependency</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><p>前端页面配合 <code>@mango/grid-layout</code> 使用：</p><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">gridLayoutPersonalApi.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">getPersonal</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;admin-home-workbench&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">gridLayoutPersonalApi.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">savePersonal</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">({ pageCode, layoutJson });</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">gridLayoutPersonalApi.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">resetPersonal</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;admin-home-workbench&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><p>业务接入时需要保持 <code>pageCode</code> 稳定。默认布局由前端业务页面维护；当查询个人布局为空时，前端使用默认布局展示。</p><h2 id="_4-配置说明" tabindex="-1">4. 配置说明 <a class="header-anchor" href="#_4-配置说明" aria-label="Permalink to &quot;4. 配置说明&quot;">​</a></h2><p>当前版本随 starter 自动装配，不提供额外业务配置项。</p><table tabindex="0"><thead><tr><th>配置入口</th><th>字段 / Key</th><th>默认值</th><th>含义</th><th>影响行为</th><th>源码入口</th></tr></thead><tbody><tr><td>Maven dependency</td><td><code>mango-grid-layout-starter</code></td><td>未引入</td><td>启用个人布局 HTTP 接口和服务</td><td>引入后注册 Controller、Service 和 Mapper</td><td><code>mango-grid-layout-starter/pom.xml</code></td></tr><tr><td>请求参数</td><td><code>pageCode</code></td><td>无</td><td>页面唯一编码</td><td>决定当前用户保存或读取哪一份布局</td><td><code>GridLayoutPersonalQuery</code></td></tr><tr><td>请求体</td><td><code>layoutJson</code></td><td>无</td><td>前端布局 JSON 字符串</td><td>保存用户拖拽后的布局结果</td><td><code>SaveGridLayoutPersonalCommand</code></td></tr></tbody></table><h2 id="_5-api-与扩展" tabindex="-1">5. API 与扩展 <a class="header-anchor" href="#_5-api-与扩展" aria-label="Permalink to &quot;5. API 与扩展&quot;">​</a></h2><p>HTTP 接口：</p><table tabindex="0"><thead><tr><th>方法</th><th>地址</th><th>说明</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/grid-layout/personal?pageCode=...</code></td><td>查询当前登录人的页面布局</td></tr><tr><td><code>PUT</code></td><td><code>/grid-layout/personal</code></td><td>保存当前登录人的页面布局</td></tr><tr><td><code>DELETE</code></td><td><code>/grid-layout/personal?pageCode=...</code></td><td>删除当前登录人的页面布局</td></tr></tbody></table><p>Java API：</p><table tabindex="0"><thead><tr><th>API</th><th>说明</th></tr></thead><tbody><tr><td><code>GridLayoutPersonalApi#getPersonal</code></td><td>查询当前登录人的页面布局</td></tr><tr><td><code>GridLayoutPersonalApi#savePersonal</code></td><td>保存当前登录人的页面布局</td></tr><tr><td><code>GridLayoutPersonalApi#deletePersonal</code></td><td>删除当前登录人的页面布局</td></tr></tbody></table><p>常用入参：</p><table tabindex="0"><thead><tr><th>类型</th><th>字段</th><th>说明</th></tr></thead><tbody><tr><td><code>GridLayoutPersonalQuery</code></td><td><code>pageCode</code></td><td>页面编码</td></tr><tr><td><code>SaveGridLayoutPersonalCommand</code></td><td><code>pageCode</code></td><td>页面编码</td></tr><tr><td><code>SaveGridLayoutPersonalCommand</code></td><td><code>layoutJson</code></td><td>布局 JSON 字符串</td></tr></tbody></table><p>模块扩展优先通过前端小组件库和业务页面编排完成。后端模块不内置业务小组件注册表，不接管业务权限策略。</p><h2 id="_6-数据与初始化" tabindex="-1">6. 数据与初始化 <a class="header-anchor" href="#_6-数据与初始化" aria-label="Permalink to &quot;6. 数据与初始化&quot;">​</a></h2><p>本模块使用 Flyway migration 初始化数据表。</p><table tabindex="0"><thead><tr><th>类型</th><th>位置</th><th>初始化内容</th><th>幂等键 / 唯一键</th><th>生效时机</th></tr></thead><tbody><tr><td>Flyway migration</td><td><code>mango-grid-layout-core/src/main/resources/db/migration/grid-layout/V1__init_grid_layout.sql</code></td><td>创建 <code>mango_user_grid_layout</code> 数据表</td><td><code>tenant_id + user_id + page_code</code></td><td>应用启动时由 Flyway 执行</td></tr></tbody></table><p>数据表：</p><table tabindex="0"><thead><tr><th>表名</th><th>说明</th></tr></thead><tbody><tr><td><code>mango_user_grid_layout</code></td><td>保存当前租户、当前用户、指定页面编码下的个人布局 JSON</td></tr></tbody></table><p>关键字段：</p><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td><code>tenant_id</code></td><td>当前登录租户</td></tr><tr><td><code>user_id</code></td><td>当前登录用户</td></tr><tr><td><code>page_code</code></td><td>页面编码</td></tr><tr><td><code>layout_json</code></td><td>前端布局 JSON 字符串</td></tr></tbody></table><p>模块不提供默认布局初始化数据。恢复默认布局时删除个人配置，由前端业务页面重新使用默认布局。</p><h2 id="_7-管理入口" tabindex="-1">7. 管理入口 <a class="header-anchor" href="#_7-管理入口" aria-label="Permalink to &quot;7. 管理入口&quot;">​</a></h2><p>本模块不新增后台菜单页面，不新增按钮权限码，也不新增默认套餐或角色授权数据。</p><table tabindex="0"><thead><tr><th>菜单 / 页面</th><th>component key</th><th>权限码</th><th>入库来源</th><th>默认套餐 / 角色</th><th>后端校验入口</th></tr></thead><tbody><tr><td>无独立管理页面</td><td>无</td><td>无新增</td><td>无</td><td>无新增</td><td><code>GridLayoutPersonalController</code> / <code>GridLayoutPersonalService</code></td></tr></tbody></table><p>接口使用登录访问模式，不需要给每个角色或用户单独配置权限。租户和用户来自 <code>MangoContextHolder</code>，前端不传 <code>tenantId</code> 和 <code>userId</code>。业务侧的小组件权限、菜单权限和数据权限在调用布局组件前完成过滤，本模块只保存当前登录人的布局结果。</p><p>这里的“个人布局”只包括组件位置、尺寸、页面编码和布局 JSON，不保存业务小组件数据。例如“我的待办”“我的流程”“统计卡片”的业务数据仍由各自业务接口提供，并继续走对应业务权限和数据权限。保存布局本身是基础体验，业务小组件是否可见、是否可查询数据，不由 <code>mango-grid-layout</code> 决定。</p><h2 id="_8-快速开始" tabindex="-1">8. 快速开始 <a class="header-anchor" href="#_8-快速开始" aria-label="Permalink to &quot;8. 快速开始&quot;">​</a></h2><p>业务接入最小闭环：</p><ol><li>后端应用引入 <code>mango-grid-layout-starter</code>。</li><li>数据库执行 <code>grid-layout</code> Flyway migration。</li><li>前端页面定义稳定的 <code>pageCode</code>。</li><li>前端页面传入默认布局和可用小组件列表。</li><li>页面加载时查询个人布局；没有个人布局时使用前端默认布局。</li><li>用户手动保存后写入个人布局。</li><li>用户恢复默认时删除个人布局。</li></ol><p>后端核心测试：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mvn</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mango/mango-platform/mango-grid-layout/mango-grid-layout-core/pom.xml</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span></span></code></pre></div><p>后端模块编译安装：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mvn</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mango/pom.xml</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -pl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mango-platform/mango-grid-layout/mango-grid-layout-starter</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -am</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -DskipTests</span></span></code></pre></div><h2 id="_9-返回字段" tabindex="-1">9. 返回字段 <a class="header-anchor" href="#_9-返回字段" aria-label="Permalink to &quot;9. 返回字段&quot;">​</a></h2><p><code>GridLayoutPersonalVO</code> 常用字段：</p><table tabindex="0"><thead><tr><th>字段</th><th>说明</th><th>是否建议业务入库</th></tr></thead><tbody><tr><td><code>id</code></td><td>个人布局记录 ID</td><td>后端维护</td></tr><tr><td><code>tenantId</code></td><td>当前租户 ID</td><td>后端维护</td></tr><tr><td><code>userId</code></td><td>当前用户 ID</td><td>后端维护</td></tr><tr><td><code>pageCode</code></td><td>页面编码</td><td>业务页面传入</td></tr><tr><td><code>layoutJson</code></td><td>布局 JSON 字符串</td><td>后端保存</td></tr><tr><td><code>createdAt</code></td><td>创建时间</td><td>后端维护</td></tr><tr><td><code>updatedAt</code></td><td>更新时间</td><td>后端维护</td></tr></tbody></table><p>业务模块通常不需要另建布局表；按页面编码使用本模块保存当前登录人的个人布局即可。</p><h2 id="_10-问题排查" tabindex="-1">10. 问题排查 <a class="header-anchor" href="#_10-问题排查" aria-label="Permalink to &quot;10. 问题排查&quot;">​</a></h2><table tabindex="0"><thead><tr><th>问题</th><th>排查方向</th></tr></thead><tbody><tr><td>查询返回为空</td><td>当前用户在该 <code>pageCode</code> 下没有保存过个人布局，前端应使用默认布局</td></tr><tr><td>保存失败且提示页面编码不一致</td><td>检查请求 <code>pageCode</code> 与 <code>layoutJson.pageCode</code> 是否一致</td></tr><tr><td>保存失败且提示宽度超出 12 栅格</td><td>检查布局项 <code>x + w</code> 是否大于 <code>12</code></td></tr><tr><td>恢复默认后仍显示旧布局</td><td>检查删除接口是否成功，前端是否清空个人布局并重新使用默认布局</td></tr><tr><td>不同用户看到同一布局</td><td>检查登录上下文中的 <code>tenantId</code>、<code>userId</code> 是否正确，以及唯一键是否生效</td></tr></tbody></table><h2 id="_11-相关文档" tabindex="-1">11. 相关文档 <a class="header-anchor" href="#_11-相关文档" aria-label="Permalink to &quot;11. 相关文档&quot;">​</a></h2><ul><li><a href="./../../../mango-pmo/rules/08-capability-docs">能力说明维护规范</a></li><li><a href="./../../../mango-pmo/rules/backend/10-dev-flow">后端开发流程</a></li><li><a href="./../../../mango-pmo/rules/backend/03-api">后端 API 规范</a></li><li><a href="./../../../mango-pmo/rules/frontend/03-component-development">前端组件开发规范</a></li><li><a href="https://github.com/HardyDou/mango/blob/main/mango-ui/packages/grid-layout/README.md" target="_blank" rel="noreferrer">@mango/grid-layout 前端包 README</a></li><li><a href="https://github.com/HardyDou/mango/blob/main/mango-docs/designs/mango-grid-layout-package-adr.md" target="_blank" rel="noreferrer">@mango/grid-layout 独立包定位 ADR</a></li><li><a href="https://github.com/HardyDou/mango/blob/main/mango-docs/designs/mango-grid-layout-workbench-design.md" target="_blank" rel="noreferrer">工作台自定义布局设计方案</a></li><li><a href="https://github.com/HardyDou/mango/blob/main/mango-docs/plans/2026-06-15-grid-layout-workbench-delivery-ledger.md" target="_blank" rel="noreferrer">工作台自定义布局交付台账</a></li></ul>`,51)])])}const k=d(i,[["render",r]]);export{g as __pageData,k as default};
